    private static readonly Lazy<FoodSearchIndex> _index = new(
        () => new FoodSearchIndex(Foods), isThreadSafe: true);

    public static List<FoodProductDto> Search(string query, int maxResults = 10)
    {
        if (string.IsNullOrWhiteSpace(query)) return [];
        return _index.Value.Search(query, maxResults);
    }

    private static FoodProductDto F(string name, int cal, decimal protein, decimal carbs, decimal fat, decimal fiber, decimal sugar, decimal sodium) =>
        new()
        {
            Name = name,
            Calories100g = cal,
            Protein100g = protein,
            Carbs100g = carbs,
            Fat100g = fat,
            Fiber100g = fiber,
            Sugar100g = sugar,
            Sodium100g = sodium,
            DataSource = "USDA",
        };
}
